"use client";

import React, { useRef, useCallback, useEffect } from "react";

interface RichTextEditorProps {
    value: string;
    onChange: (val: string) => void;
    placeholder?: string;
    minRows?: number;
}

export default function RichTextEditor({ value, onChange, placeholder, minRows = 3 }: RichTextEditorProps) {
    const editorRef = useRef<HTMLDivElement>(null);
    const isInternalChange = useRef(false);

    useEffect(() => {
        if (editorRef.current && !isInternalChange.current) {
            if (editorRef.current.innerHTML !== value) {
                editorRef.current.innerHTML = value || "";
            }
        }
        isInternalChange.current = false;
    }, [value]);

    const handleInput = useCallback(() => {
        if (editorRef.current) {
            isInternalChange.current = true;
            onChange(editorRef.current.innerHTML);
        }
    }, [onChange]);

    const exec = (cmd: string, val?: string) => {
        document.execCommand(cmd, false, val);
        editorRef.current?.focus();
        handleInput();
    };

    const addLink = () => {
        const url = prompt("URL girin:", "https://");
        if (url) exec("createLink", url);
    };

    const isActive = (cmd: string) => {
        try { return document.queryCommandState(cmd); } catch { return false; }
    };

    const btnCls = (active: boolean) =>
        `w-7 h-7 rounded flex items-center justify-center text-xs font-bold transition ${active ? "bg-blue-600 text-white" : "bg-gray-100 text-gray-600 hover:bg-gray-200"}`;

    return (
        <div className="rounded-lg border border-gray-200 overflow-hidden bg-white focus-within:ring-2 focus-within:ring-blue-500/20 focus-within:border-blue-400 transition">
            {/* Toolbar */}
            <div className="flex items-center gap-1 px-2 py-1.5 border-b border-gray-100 bg-gray-50/50">
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("bold"); }} className={btnCls(isActive("bold"))} title="Kalın">
                    <strong>B</strong>
                </button>
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("italic"); }} className={btnCls(isActive("italic"))} title="İtalik">
                    <em>I</em>
                </button>
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("underline"); }} className={btnCls(isActive("underline"))} title="Altı Çizili">
                    <span className="underline">U</span>
                </button>
                <div className="w-px h-4 bg-gray-200 mx-0.5" />
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("insertUnorderedList"); }} className={btnCls(isActive("insertUnorderedList"))} title="Liste">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /><circle cx="1" cy="6" r="1" fill="currentColor" /><circle cx="1" cy="12" r="1" fill="currentColor" /><circle cx="1" cy="18" r="1" fill="currentColor" /></svg>
                </button>
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("insertOrderedList"); }} className={btnCls(isActive("insertOrderedList"))} title="Numaralı Liste">
                    <span className="text-[9px]">1.</span>
                </button>
                <div className="w-px h-4 bg-gray-200 mx-0.5" />
                <button type="button" onMouseDown={e => { e.preventDefault(); addLink(); }} className={btnCls(false)} title="Link Ekle">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                </button>
                <button type="button" onMouseDown={e => { e.preventDefault(); exec("removeFormat"); }} className="w-7 h-7 rounded flex items-center justify-center text-[9px] text-gray-400 hover:text-red-500 hover:bg-red-50 transition" title="Formatı Temizle">
                    ✕
                </button>
            </div>

            {/* Editable Area */}
            <div
                ref={editorRef}
                contentEditable
                onInput={handleInput}
                className="px-3 py-2 text-sm text-gray-800 outline-none min-h-[4rem] prose prose-sm max-w-none [&_a]:text-blue-600 [&_a]:underline [&_b]:font-bold [&_i]:italic [&_u]:underline [&_ul]:list-disc [&_ul]:ml-4 [&_ol]:list-decimal [&_ol]:ml-4"
                style={{ minHeight: `${minRows * 1.5}rem` }}
                data-placeholder={placeholder}
                suppressContentEditableWarning
            />

            <style jsx>{`
                [data-placeholder]:empty:before {
                    content: attr(data-placeholder);
                    color: #9ca3af;
                    pointer-events: none;
                }
            `}</style>
        </div>
    );
}
